const raw = $input.first().json;
const text = String(raw.query ?? raw.chatInput ?? raw.issue_number ?? raw.input ?? '').trim();
const m = text.match(/#?(\d{3,6})/);
if (!m) {
  return [{ json: { issueNumber: null, response: 'Provide an issue number (e.g. 14361 or #14361).' } }];
}
return [{ json: { issueNumber: parseInt(m[1], 10) } }];

const parsed = $('Parse input').first().json;
if (!parsed.issueNumber) {
  return [{ json: { response: parsed.response } }];
}
const issueNumber = parsed.issueNumber;
const raw = await this.helpers.httpRequestWithAuthentication.call(this, 'githubApi', {
  method: 'GET',
  url: `https://api.github.com/repos/n8n-io/n8n/issues/${issueNumber}/comments?per_page=100`,
  json: true,
});
const skip = new Set(['dependabot[bot]', 'n8n-io[bot]', 'github-actions[bot]']);
const comments = (Array.isArray(raw) ? raw : []).filter((c) => c.body && !skip.has(c.user?.login)).slice(0, 30);
if (!comments.length) {
  return [{ json: { response: `No comments found for #${issueNumber}.` } }];
}
const lines = comments.map((c) => {
  const who = c.user?.login ?? 'unknown';
  const assoc = c.author_association ?? '';
  const body = (c.body ?? '').replace(/\s+/g, ' ').slice(0, 600);
  return `**@${who}** (${assoc}): ${body}`;
});
return [{
  json: {
    response: `# Comments on #${issueNumber} (${comments.length} shown, newest last)\n\n${lines.join('\n\n')}`,
  },
}];
